func _powerset(x any) any {
	items := _dedupe(_slice(x))
	n := len(items)
	subsets := make([]any, 0, 1<<n)
	for mask := 0; mask < (1 << n); mask++ {
		sub := make([]any, 0, n)
		for i := 0; i < n; i++ {
			if mask&(1<<i) != 0 {
				sub = append(sub, items[i])
			}
		}
		subsets = append(subsets, _Set(sub))
	}
	return _Set(subsets)
}

