func _index(base, idx any) any {
	switch b := base.(type) {
	case []any:
		if f, ok := _toF(idx); ok {
			i := int(f)
			if i >= 0 && i < len(b) {
				return b[i]
			}
		}
	case _Set:
		if f, ok := _toF(idx); ok {
			i := int(f)
			if i >= 0 && i < len(b) {
				return b[i]
			}
		}
	case map[string]any:
		return b[_str(idx)]
	case string:
		if f, ok := _toF(idx); ok {
			rs := []rune(b)
			i := int(f)
			if i >= 0 && i < len(rs) {
				return string(rs[i])
			}
		}
	}
	return nil
}

