func _abs(x any) any {
	// _toF folds json.Number in; mirrors TS's Math.abs(Number(x)).
	if f, ok := _toF(x); ok {
		return math.Abs(f)
	}
	return math.NaN()
}

func _now() any {
	// Epoch seconds (float64) so `now() - minutes(15)` is numeric arithmetic.
	// Aligns with _mul-based time-unit functions which return numeric seconds.
	return float64(time.Now().UTC().Unix())
}

func _sha256Hex(s any) any {
	// _str canonicalizes numbers (json.Number "2", int64 2, and float64 2
	// all hash as "2") so decoded and computed values agree.
	sum := sha256.Sum256([]byte(_str(s)))
	return hex.EncodeToString(sum[:])
}
